import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route, useNavigate, useParams } from 'react-router-dom';
import Navbar from './components/Navbar/Navbar';
import Footer from './components/Footer/Footer';
import Hero from './features/landing/Hero';
import HowItWorks from './features/landing/HowItWorks';
import JobServices from './features/landing/JobServices';
import Testimonials from './features/landing/Testimonials';
import CTA from './features/landing/CTA';
import JobListContainer from './features/eksplorasi/JobListContainer';
import Login from './components/auth/Login';
import Register from './components/auth/Register';
import JobDetail from './components/jobs/JobDetail';

// Tambahkan Import untuk komponen HRD
import JobPublisher from './features/hrd/JobPublisher';
import CompanyBrandingForm from './features/hrd/CompanyBrandingForm';

const JobDetailWrapper = () => {
    const { id } = useParams();
    return <JobDetail job={{ id, title: 'Lowongan Detail', company: 'PasukanYerusSolo' }} />;
};

const App = () => {
    const [isAuthenticated, setIsAuthenticated] = useState(!!localStorage.getItem('token'));
    // Ambil role dari localStorage jika ada
    const [userRole, setUserRole] = useState(localStorage.getItem('role') || null);

    const handleLogout = () => {
        localStorage.removeItem('token');
        localStorage.removeItem('role');
        setIsAuthenticated(false);
        setUserRole(null);
        window.location.href = '/';
    };

    return (
        <div style={{ backgroundColor: '#0c0a09', minHeight: '100vh', color: '#fff' }}>
            <Navbar 
                isAuthenticated={isAuthenticated} 
                userRole={userRole} 
                handleLogout={handleLogout} 
            />
            <main>
                <Routes>
                    <Route path="/" element={<><Hero /><HowItWorks /><JobServices /><section style={{ maxWidth: '900px', margin: '40px auto', padding: '0 20px' }}><h2 style={{ fontSize: '20px', fontWeight: '700', color: '#fef3c7', marginBottom: '20px' }}>Lowongan Terbaru</h2><JobListContainer variant="simple" limit={4} /></section><Testimonials /><CTA /></>} />
                    <Route path="/eksplorasi" element={<div style={{ maxWidth: '900px', margin: '40px auto', padding: '0 20px' }}><h1 style={{ fontSize: '24px', marginBottom: '20px', color: '#fef3c7' }}>Semua Lowongan Kerja</h1><JobListContainer variant="full" /></div>} />
                    <Route path="/job/:id" element={<JobDetailWrapper />} />
                    <Route path="/login" element={<Login onLoginSuccess={() => { setIsAuthenticated(true); setUserRole(localStorage.getItem('role')); }} />} />
                    <Route path="/register" element={<Register />} />
                    {/* Rute HRD */}
                    <Route path="/hrd/dashboard" element={<JobPublisher />} />
                    <Route path="/hrd/branding" element={<CompanyBrandingForm />} />
                </Routes>
            </main>
            <Footer />
        </div>
    );
};

const AppWrapper = () => (
    <Router>
        <App />
    </Router>
);

export default AppWrapper;
